function parseQueryString(value) {
  if (value === undefined || value === null || value === '') return {}
  if (typeof value === 'object' && !Array.isArray(value)) return value
  const text = String(value).trim()
  if (!text) return {}
  if (text.startsWith('{')) {
    try {
      const parsed = JSON.parse(text)
      return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {}
    } catch {}
  }
  const source = text.startsWith('?') ? text.slice(1) : text
  const result = {}
  for (const pair of source.split('&')) {
    if (!pair) continue
    const separatorIndex = pair.indexOf('=')
    const rawKey = separatorIndex >= 0 ? pair.slice(0, separatorIndex) : pair
    const rawValue = separatorIndex >= 0 ? pair.slice(separatorIndex + 1) : ''
    const key = decodeURIComponent(rawKey.replace(/\+/g, ' ')).trim()
    const paramValue = decodeURIComponent(rawValue.replace(/\+/g, ' ')).trim()
    if (!key || paramValue === '') continue
    if (result[key] === undefined) result[key] = paramValue
    else if (Array.isArray(result[key])) result[key].push(paramValue)
    else result[key] = [result[key], paramValue]
  }
  return result
}

function parseObject(value) {
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value)
      return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : parseQueryString(value)
    } catch {
      return parseQueryString(value)
    }
  }
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {}
}

function readInput() {
  const raw = parseObject($json)
  const input = { ...raw }
  for (const key of ['json', 'body', 'data', 'input', 'workflowInputs', 'parameters', 'args']) {
    Object.assign(input, parseObject(raw[key]))
  }
  Object.assign(input, parseQueryString(raw.query))
  Object.assign(input, parseQueryString(raw.queryString))
  return input
}

function present(value) {
  if (Array.isArray(value)) return value.length > 0 ? value : undefined
  return value !== undefined && value !== null && value !== '' ? value : undefined
}

function toInteger(value) {
  const normalized = present(value)
  if (normalized === undefined || Array.isArray(normalized)) return undefined
  const parsed = Number(normalized)
  return Number.isInteger(parsed) ? parsed : undefined
}

function toBooleanString(value) {
  const normalized = present(value)
  if (normalized === undefined || Array.isArray(normalized)) return undefined
  if (normalized === true || normalized === 1 || normalized === '1' || String(normalized).toLowerCase() === 'true') return 'true'
  if (normalized === false || normalized === 0 || normalized === '0' || String(normalized).toLowerCase() === 'false') return 'false'
  return undefined
}

function assign(params, key, value, type = 'string') {
  const normalized = present(value)
  if (normalized === undefined) return
  if (type === 'number') {
    const numberValue = toInteger(normalized)
    if (numberValue !== undefined) params[key] = String(numberValue)
    return
  }
  if (type === 'boolean') {
    const booleanValue = toBooleanString(normalized)
    if (booleanValue !== undefined) params[key] = booleanValue
    return
  }
  if (Array.isArray(normalized)) params[key] = normalized.map(String).filter(Boolean)
  else params[key] = String(normalized).trim()
}

function encodeQuery(params) {
  const parts = []
  for (const [key, value] of Object.entries(params)) {
    if (value === undefined || value === null || value === '') continue
    const values = Array.isArray(value) ? value : [value]
    for (const item of values) parts.push(encodeURIComponent(key) + '=' + encodeURIComponent(String(item)))
  }
  return parts.join('&')
}

function buildUrl(baseUrl, endpoint, params) {
  const query = encodeQuery(params)
  return query ? baseUrl + endpoint + '?' + query : baseUrl + endpoint
}

const config = {
  "endpoint": "/rooms",
  "allowedParams": [
    {
      "name": "facilityId",
      "type": "number"
    },
    {
      "name": "roomTypeId",
      "type": "number"
    },
    {
      "name": "roomClassId",
      "type": "number"
    },
    {
      "name": "dataStatus",
      "type": "number"
    },
    {
      "name": "periodFrom",
      "type": "string"
    },
    {
      "name": "periodTo",
      "type": "string"
    },
    {
      "name": "page",
      "type": "number"
    },
    {
      "name": "limit",
      "type": "number"
    },
    {
      "name": "orderBy",
      "type": "string"
    },
    {
      "name": "order",
      "type": "string"
    }
  ],
  "aliases": [
    {
      "from": "from",
      "to": "periodFrom"
    },
    {
      "from": "to",
      "to": "periodTo"
    }
  ],
  "copyRules": [
    {
      "from": "date",
      "to": "periodFrom"
    },
    {
      "from": "date",
      "to": "periodTo"
    }
  ],
  "requiredParams": [
    "periodFrom",
    "periodTo"
  ],
  "defaults": {
    "dataStatus": 1,
    "limit": 50
  },
  "keepFields": [
    "roomType"
  ]
}
const input = readInput()
const apiBaseUrl = 'http://host.docker.internal:3000/api/v1'
const params = {}

for (const alias of config.aliases ?? []) {
  const sourceValue = present(input[alias.from])
  if (sourceValue !== undefined && present(input[alias.to]) === undefined) input[alias.to] = sourceValue
}

for (const field of config.allowedParams ?? []) {
  assign(params, field.name, input[field.name], field.type ?? 'string')
}

for (const [key, value] of Object.entries(config.defaults ?? {})) {
  if (params[key] === undefined) params[key] = String(value)
}

for (const rule of config.copyRules ?? []) {
  const sourceValue = present(input[rule.from])
  if (sourceValue !== undefined && params[rule.to] === undefined) assign(params, rule.to, sourceValue, rule.type ?? 'string')
}

const missing = []
for (const key of config.requiredParams ?? []) {
  if (present(params[key]) === undefined) missing.push(key)
}

const endpoint = config.pathParam
  ? config.endpointPrefix + '/' + encodeURIComponent(String(params[config.pathParam] ?? ''))
  : config.endpoint
const cleanParams = config.pathParam ? Object.fromEntries(Object.entries(params).filter(([key]) => key !== config.pathParam)) : params
const apiUrl = missing.length === 0 ? buildUrl(apiBaseUrl, endpoint, cleanParams) : null
const warnings = missing.map((key) => 'Missing required query param: ' + key)
const kept = {}
for (const key of config.keepFields ?? []) kept[key] = input[key]
return [{ json: { rawInput: input, params, queryString: encodeQuery(params), apiUrl, canCallApi: missing.length === 0, warnings, apiBaseUrl, internalToken: 'dev-internal-token', ...kept } }]

function normalizeText(value) {
  return String(value ?? '').trim().toLowerCase()
}

function matchesRoomType(room, roomType) {
  const expected = normalizeText(roomType)
  if (!expected) return true
  return normalizeText(room.roomTypeName).includes(expected) || normalizeText(room.roomClassName).includes(expected)
}

function extractRows(result) {
  return Array.isArray(result)
    ? result
    : Array.isArray(result.availableRooms)
      ? result.availableRooms
      : Array.isArray(result.rooms)
        ? result.rooms
        : Array.isArray(result.data)
          ? result.data
          : Array.isArray(result.items)
            ? result.items
            : []
}

const input = $('Prepare Input').first().json
const rows = extractRows($json)
const availableRooms = rows.filter((room) => matchesRoomType(room, input.roomType))
return [{ json: { availableRooms, sources: [{ type: 'api', name: 'GET /rooms?periodFrom&periodTo' }] } }]
